package pl.msurvival.lobby;
import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.entity.Player;import org.bukkit.event.*;import org.bukkit.event.block.*;import org.bukkit.event.entity.*;import org.bukkit.event.inventory.*;import org.bukkit.event.player.*;import org.bukkit.inventory.*;import org.bukkit.inventory.meta.*;import org.bukkit.persistence.*;import org.bukkit.plugin.java.JavaPlugin;import java.util.*;
public final class MSurvivalLobby extends JavaPlugin implements Listener{private NamespacedKey k;public void onEnable(){saveDefaultConfig();k=new NamespacedKey(this,"lobby_item");Bukkit.getPluginManager().registerEvents(this,this);} public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(!(s instanceof Player p))return true;String n=c.getName().toLowerCase(Locale.ROOT);if(n.equals("lobby")){toLobby(p);return true;}if(n.equals("survival")){toSurvival(p);return true;}if(n.equals("menu")){open(p);return true;}if(n.equals("setlobby")){if(!p.hasPermission("msurvival.lobby.admin"))return deny(p);saveLoc("lobby",p.getLocation());p.sendMessage(msg("set-lobby"));return true;}if(n.equals("setsurvival")){if(!p.hasPermission("msurvival.lobby.admin"))return deny(p);saveLoc("survival",p.getLocation());p.sendMessage(msg("set-survival"));return true;}return true;}@EventHandler public void join(PlayerJoinEvent e){Bukkit.getScheduler().runTaskLater(this,()->{if(e.getPlayer().isOnline())toLobby(e.getPlayer());},10L);}private void toLobby(Player p){Location l=loc("lobby",getConfig().getString("worlds.lobby","Lobby"));if(l!=null)p.teleport(l);remove(p);give(p);p.setFoodLevel(20);p.sendMessage(msg("lobby"));}private void toSurvival(Player p){remove(p);Location l=p.getBedSpawnLocation();if(l==null)l=loc("survival",getConfig().getString("worlds.survival","world"));if(l!=null)p.teleport(l);p.sendMessage(msg("survival"));}private void give(Player p){p.getInventory().setItem(getConfig().getInt("items.compass-slot",4), compass());}private ItemStack compass(){ItemStack i=new ItemStack(Material.COMPASS);ItemMeta m=i.getItemMeta();m.setDisplayName(color(getConfig().getString("items.compass-name")));m.getPersistentDataContainer().set(k,PersistentDataType.STRING,"1");i.setItemMeta(m);return i;}private boolean lobbyItem(ItemStack i){return i!=null&&i.hasItemMeta()&&i.getItemMeta().getPersistentDataContainer().has(k,PersistentDataType.STRING);}private void remove(Player p){ItemStack[] c=p.getInventory().getContents();for(int i=0;i<c.length;i++)if(lobbyItem(c[i]))p.getInventory().setItem(i,null);}@EventHandler public void interact(PlayerInteractEvent e){if(lobbyItem(e.getItem())){e.setCancelled(true);open(e.getPlayer());}}private void open(Player p){Inventory inv=Bukkit.createInventory(null,27,color("&6&lMSURVIVAL MENU"));ItemStack g=item(Material.BLACK_STAINED_GLASS_PANE," ");for(int i=0;i<27;i++)inv.setItem(i,g);inv.setItem(10,item(Material.NETHER_STAR,"&e&lLobby"));inv.setItem(12,item(Material.GRASS_BLOCK,"&a&lSurvival"));inv.setItem(14,item(Material.TRIPWIRE_HOOK,"&6&lKlucze"));inv.setItem(16,item(Material.CHEST,"&b&lE-Kity"));p.openInventory(inv);}@EventHandler public void click(InventoryClickEvent e){if(!(e.getWhoClicked() instanceof Player p))return;if(e.getView().getTitle().equals(color("&6&lMSURVIVAL MENU"))){e.setCancelled(true);ItemStack it=e.getCurrentItem();if(it==null||!it.hasItemMeta())return;String name=ChatColor.stripColor(it.getItemMeta().getDisplayName()).toLowerCase(Locale.ROOT);p.closeInventory();if(name.contains("lobby"))toLobby(p);else if(name.contains("survival"))toSurvival(p);else if(name.contains("klucze"))p.performCommand("keysmenu");else if(name.contains("e-kity"))p.performCommand("kits");return;}if(inLobby(p))e.setCancelled(true);}@EventHandler public void br(BlockBreakEvent e){if(inLobby(e.getPlayer()))e.setCancelled(true);}@EventHandler public void bp(BlockPlaceEvent e){if(inLobby(e.getPlayer()))e.setCancelled(true);}@EventHandler public void dr(PlayerDropItemEvent e){if(inLobby(e.getPlayer()))e.setCancelled(true);}@EventHandler public void dmg(EntityDamageEvent e){if(e.getEntity() instanceof Player p&&inLobby(p))e.setCancelled(true);}@EventHandler public void food(FoodLevelChangeEvent e){if(e.getEntity() instanceof Player p&&inLobby(p)){e.setCancelled(true);p.setFoodLevel(20);}}private boolean inLobby(Player p){return p.getWorld().getName().equalsIgnoreCase(getConfig().getString("worlds.lobby","Lobby"));}private ItemStack item(Material mat,String n){ItemStack i=new ItemStack(mat);ItemMeta m=i.getItemMeta();m.setDisplayName(color(n));i.setItemMeta(m);return i;}private void saveLoc(String path,Location l){getConfig().set(path+".x",l.getX());getConfig().set(path+".y",l.getY());getConfig().set(path+".z",l.getZ());getConfig().set(path+".yaw",l.getYaw());getConfig().set(path+".pitch",l.getPitch());saveConfig();}private Location loc(String path,String wn){World w=Bukkit.getWorld(wn);return w==null?null:new Location(w,getConfig().getDouble(path+".x"),getConfig().getDouble(path+".y"),getConfig().getDouble(path+".z"),(float)getConfig().getDouble(path+".yaw"),(float)getConfig().getDouble(path+".pitch"));}private boolean deny(Player p){p.sendMessage(msg("no-permission"));return true;}private String msg(String x){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+x,""));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
